func SetLang(l Lang) {
	currentLangMu.Lock()
	defer currentLangMu.Unlock()
	currentLang = l
}

func GetLang() Lang {
	currentLangMu.RLock()
	defer currentLangMu.RUnlock()
	return currentLang
}

func Translations() map[Lang]map[string]string {
	cp := make(map[Lang]map[string]string, len(translations))
	for k, v := range translations {
		inner := make(map[string]string, len(v))
		for ik, iv := range v {
			inner[ik] = iv
		}
	cp[k] = inner
	}
	return cp
}

// T returns the translation for key in the current language, or the key itself if missing.
func T(key string) string {
	currentLangMu.RLock()
	lang := currentLang
	currentLangMu.RUnlock()
	return TFor(key, lang)
}

// TFor returns the translation for key in the specified language,
// falling back to English, then to the key itself.
func TFor(key string, lang Lang) string {
	currentLangMu.RLock()
	defer currentLangMu.RUnlock()
	if val, ok := translations[lang][key]; ok {
		return val
	}
	if val, ok := translations[LangEN][key]; ok {
		return val
	}
	return key
}

// SetTranslations overrides translations for a given language.
func SetTranslations(lang Lang, m map[string]string) {
	currentLangMu.Lock()
	defer currentLangMu.Unlock()
	if m == nil {
		return
	}
	translations[lang] = m
}

// LoadLangFromToml loads translations from a TOML file.
func LoadLangFromToml(path string, lang Lang) error {
	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()
	m := translations[lang]
	if m == nil {
		m = map[string]string{}
		translations[lang] = m
	}
	scanner := bufio.NewScanner(f)
	keyRe := regexp.MustCompile(`^([a-z0-9_.]+)\s*=\s*"([^"]*)"\s*$`)
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" || strings.HasPrefix(line, "#") {
			continue
		}
		matches := keyRe.FindStringSubmatch(line)
		if len(matches) == 3 {
			m[matches[1]] = matches[2]
		}
	}
	return scanner.Err()
}